import React, { useState } from "react";

const emptyForm = { plate: "", ownerName: "", ownerEmail: "", vehicleModel: "" };

function AddVehicleForm() {
  const [form, setForm]       = useState(emptyForm);
  const [submitted, setSubmitted] = useState(false);
  const [error, setError]     = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError("");
    setSubmitted(false);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const { plate, ownerName, ownerEmail, vehicleModel } = form;
    if (!plate || !ownerName || !ownerEmail || !vehicleModel) {
      setError("All fields are required.");
      return;
    }
    // In real use: POST to Flask /api/add-vehicle
    console.log("Submitting stolen vehicle:", form);
    setSubmitted(true);
    setForm(emptyForm);
  };

  return (
    <div className="panel form-panel">
      <div className="panel-header">
        <h3 className="panel-title">➕ Register Stolen Vehicle</h3>
      </div>

      {submitted && (
        <div className="form-success">
          ✅ Vehicle registered successfully in the stolen vehicle database.
        </div>
      )}

      {error && <div className="form-error">⚠ {error}</div>}

      <form className="add-form" onSubmit={handleSubmit}>
        <div className="form-grid">
          <div className="form-field">
            <label>Plate Number *</label>
            <input
              name="plate" value={form.plate}
              onChange={handleChange}
              placeholder="e.g. KL34F500"
              className="form-input"
            />
          </div>

          <div className="form-field">
            <label>Vehicle Model *</label>
            <input
              name="vehicleModel" value={form.vehicleModel}
              onChange={handleChange}
              placeholder="e.g. Hyundai i10"
              className="form-input"
            />
          </div>

          <div className="form-field">
            <label>Owner Name *</label>
            <input
              name="ownerName" value={form.ownerName}
              onChange={handleChange}
              placeholder="Full name of owner"
              className="form-input"
            />
          </div>

          <div className="form-field">
            <label>Owner Email *</label>
            <input
              name="ownerEmail" value={form.ownerEmail}
              onChange={handleChange}
              placeholder="owner@email.com"
              className="form-input"
              type="email"
            />
          </div>
        </div>

        <button type="submit" className="submit-btn">
          Submit to Database
        </button>
      </form>
    </div>
  );
}

export default AddVehicleForm;
